	private void OnMinutesChanged(LineEditEventArgs args)
	{
		//IL_0044: Unknown result type (might be due to invalid IL or missing references)
		TimeLine.Text = args.Text;
		if (!double.TryParse(args.Text, out var result))
		{
			ExpiresLabel.Text = "err";
			ErrorLevel |= ErrorLevelEnum.Minutes;
			((Control)TimeLine).ModulateSelfOverride = Color.Red;
			UpdateSubmitEnabled();
		}
		else
		{
			ErrorLevel &= ~ErrorLevelEnum.Minutes;
			((Control)TimeLine).ModulateSelfOverride = null;
			TimeEntered = result;
			UpdateSubmitEnabled();
			UpdateExpiresLabel();
		}
	}

	private void OnMultiplierChanged()
	{
		TimeLine.Editable = MultiplierOption.SelectedId != 6;
		Multiplier = MultiplierOption.SelectedId switch
		{
			0 => 1u, 
			1 => 60u, 
			2 => 1440u, 
			3 => 10080u, 
			4 => 43200u, 
			5 => 525600u, 
			6 => 0u, 
			_ => throw new ArgumentOutOfRangeException("SelectedId", "Multiplier out of range"), 
		};
		UpdateExpiresLabel();
	}

	private void UpdateExpiresLabel()
	{
		uint num = (uint)(TimeEntered * (double)Multiplier);
		ExpiresLabel.Text = ((num == 0) ? (Loc.GetString("admin-note-editor-expiry-label") + " " + Loc.GetString("server-ban-string-never")) : $"{Loc.GetString("admin-note-editor-expiry-label")} {DateTime.Now + TimeSpan.FromMinutes(num):yyyy/MM/dd HH:mm:ss}");
	}

